"use client";

import React, { useState, useEffect } from "react";
import { QRCodeSVG } from "qrcode.react";

export default function EnterpriseTerminal() {
  // --- APP STATE ---
    const [step, setStep] = useState<"PAIRING" | "POS" | "PAYING">("PAIRING");
      const [pairingCode, setPairingCode] = useState("");
        const [amount, setAmount] = useState("");
          const [isPaid, setIsPaid] = useState(false);

            // --- DYNAMIC DATA (Mocked for Enterprise Demo) ---
              const [terminalData, setTerminalData] = useState({
                  outlet: "Ibadan Regional Hub",
                      staffName: "Agent #702",
                          staffPhoto: "https://api.dicebear.com/7.x/avataaars/svg?seed=Felix", 
                            });

                              // Sync with your Merchant Admin's latest registration
                                useEffect(() => {
                                    const saved = localStorage.getItem('opayque_staff');
                                        if (saved) {
                                              const staff = JSON.parse(saved);
                                                    if (staff.length > 0) {
                                                            setTerminalData(prev => ({
                                                                      ...prev,
                                                                                staffName: staff[staff.length - 1].name
                                                                                        }));
                                                                                              }
                                                                                                  }
                                                                                                    }, []);

                                                                                                      // --- HAPTIC & AUDIO FEEDBACK ---
                                                                                                        const triggerSuccessSensory = () => {
                                                                                                            // 1. VIBRATION (Mobile only: Short double pulse for 'Success')
                                                                                                                if (typeof navigator !== "undefined" && navigator.vibrate) {
                                                                                                                      navigator.vibrate([100, 50, 100]);
                                                                                                                          }

                                                                                                                              // 2. AUDIO CHIME
                                                                                                                                  const audio = new Audio("https://assets.mixkit.co/active_storage/sfx/2013/2013-preview.mp3");
                                                                                                                                      audio.play().catch(() => console.log("Audio requires user interaction first."));
                                                                                                                                          
                                                                                                                                              setIsPaid(true);
                                                                                                                                                  
                                                                                                                                                      // Auto-reset terminal after 4 seconds
                                                                                                                                                          setTimeout(() => {
                                                                                                                                                                setIsPaid(false);
                                                                                                                                                                      setStep("POS");
                                                                                                                                                                            setAmount("");
                                                                                                                                                                                }, 4000);
                                                                                                                                                                                  };

                                                                                                                                                                                    // --- LOGIC: PAIRING ---
                                                                                                                                                                                      const handlePairing = (e: React.FormEvent) => {
                                                                                                                                                                                          e.preventDefault();
                                                                                                                                                                                              if (pairingCode.length === 6) {
                                                                                                                                                                                                    setStep("POS");
                                                                                                                                                                                                        } else {
                                                                                                                                                                                                              alert("Invalid Device Authorization Code");
                                                                                                                                                                                                                  }
                                                                                                                                                                                                                    };

                                                                                                                                                                                                                      // --- UI: QR COMPONENT ---
                                                                                                                                                                                                                        const SolanaPayQR = () => {
                                                                                                                                                                                                                            const paymentUri = `solana:Gh9ZwE9pk6fGst87fM7W6oY2i7m5wR8E3j28b9yWv352?amount=${amount}&label=Opayque%20Vault`;
                                                                                                                                                                                                                                
                                                                                                                                                                                                                                    return (
                                                                                                                                                                                                                                          <div className="animate-in zoom-in duration-500 text-center">
                                                                                                                                                                                                                                                  {/* CLICK THE QR TO SIMULATE THE SUCCESS IN YOUR DEMO VIDEO */}
                                                                                                                                                                                                                                                          <div 
                                                                                                                                                                                                                                                                    className="p-8 bg-white rounded-[3.5rem] inline-block mb-8 shadow-2xl cursor-pointer active:scale-95 transition-transform border-[12px] border-zinc-900"
                                                                                                                                                                                                                                                                              onClick={triggerSuccessSensory} 
                                                                                                                                                                                                                                                                                      >
                                                                                                                                                                                                                                                                                                <QRCodeSVG
                                                                                                                                                                                                                                                                                                            value={paymentUri}
                                                                                                                                                                                                                                                                                                                        size={240}
                                                                                                                                                                                                                                                                                                                                    level="H"
                                                                                                                                                                                                                                                                                                                                                imageSettings={{
                                                                                                                                                                                                                                                                                                                                                              src: terminalData.staffPhoto,
                                                                                                                                                                                                                                                                                                                                                                            height: 55,
                                                                                                                                                                                                                                                                                                                                                                                          width: 55,
                                                                                                                                                                                                                                                                                                                                                                                                        excavate: true, // The "Hole-punch" magic
                                                                                                                                                                                                                                                                                                                                                                                                                    }}
                                                                                                                                                                                                                                                                                                                                                                                                                              />
                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="space-y-1">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <h2 className="text-5xl font-mono font-bold tracking-tighter">${amount}</h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <p className="text-[10px] text-purple-500 font-bold uppercase tracking-[0.3em] animate-pulse">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             Shielded Request Active
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         <button 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   onClick={() => setStep("POS")}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             className="mt-16 text-zinc-700 hover:text-white text-[10px] font-bold uppercase tracking-widest transition-colors"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               ← Cancel Transaction
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         <div className="min-h-screen bg-black text-white flex items-center justify-center p-6 selection:bg-purple-500/30">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               <div className="w-full max-w-md">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               {/* STEP 1: PAIRING (The Login) */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       {step === "PAIRING" && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 <div className="animate-in fade-in slide-in-from-bottom-12 duration-1000">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             <div className="text-center mb-12">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             <h1 className="text-4xl font-black italic tracking-tighter">OPAYQUE<span className="text-purple-500">.</span></h1>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             <p className="text-zinc-600 text-[9px] uppercase font-bold tracking-[0.4em] mt-2">Hardware Security Module</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     <form onSubmit={handlePairing} className="space-y-6">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   <input 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   type="text" 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   maxLength={6}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   placeholder="000000"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   value={pairingCode}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   onChange={(e) => setPairingCode(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   className="w-full bg-zinc-900/50 border border-white/5 rounded-[2.5rem] py-12 text-center text-6xl font-mono font-bold outline-none focus:border-purple-500/40 transition-all shadow-inner"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               <button className="w-full py-6 bg-white text-black rounded-[1.8rem] font-black uppercase text-[11px] tracking-widest hover:bg-zinc-200 active:scale-95 transition-all">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               Authorize Endpoint
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         </form>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   {/* STEP 2: POS (The Amount Entry) */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           {step === "POS" && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     <div className="bg-zinc-900 border border-white/5 rounded-[4rem] p-10 shadow-2xl animate-in fade-in zoom-in duration-500 relative overflow-hidden">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 <div className="absolute top-0 right-0 p-8 opacity-5 text-4xl font-black italic">POS</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         <div className="flex justify-between items-center mb-12">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         <div className="bg-white/5 px-4 py-2 rounded-full border border-white/5">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             <p className="text-[8px] font-bold uppercase text-zinc-500 tracking-widest">ID: {terminalData.staffName}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             <div className="h-2 w-2 bg-green-500 rounded-full shadow-[0_0_10px_rgba(34,197,94,0.5)]"></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     <div className="bg-black rounded-[3rem] p-12 mb-10 border border-white/5 shadow-inner">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     <p className="text-center text-[9px] font-black text-zinc-700 uppercase tracking-widest mb-6">Enter Charge (USDC)</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     <div className="flex items-center justify-center">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         <span className="text-2xl font-bold text-zinc-800 mr-2">$</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             <input 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     type="number"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             placeholder="0.00"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     value={amount}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             onChange={(e) => setAmount(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     className="bg-transparent text-7xl font-mono font-bold text-center outline-none w-full"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             autoFocus
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         <button 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         onClick={() => setStep("PAYING")}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         disabled={!amount || parseFloat(amount) <= 0}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         className="w-full py-8 bg-purple-600 rounded-[2.2rem] font-black text-2xl hover:bg-purple-500 transition-all shadow-2xl shadow-purple-500/20 disabled:opacity-10"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     GENERATE QR
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           {/* STEP 3: QR & SETTLEMENT ANIMATION */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   {step === "PAYING" && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             <div className="flex flex-col items-center">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         {isPaid ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       <div className="text-center animate-in zoom-in duration-500">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       <div className="w-28 h-28 bg-white text-black rounded-full flex items-center justify-center mx-auto mb-8 shadow-2xl shadow-white/20">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           <span className="text-5xl font-black italic">!</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           <h2 className="text-6xl font-black italic tracking-tighter mb-4 text-white">SETTLED</h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           <div className="inline-block px-4 py-2 bg-purple-500/10 border border-purple-500/20 rounded-full">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               <p className="text-purple-400 text-[10px] font-bold uppercase tracking-[0.3em]">Privacy Shield Verified</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       <SolanaPayQR />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 